select approval_id approvalId,module_name moduleName,operation_name operationName,application_info applicationInfo,
callback_data callbackData,callback_url callbackUrl,task_id taskId,operator_id operatorId,view_url viewUrl
from DGN_APPROVAL


		and module_id = #{moduleId}


		and status = #{status}


		and (status = '1' or status = '0')
